      label.className = "classical-whole-canvas-choice__label";
      label.textContent = spec.label || sourceControl.dataset.classicalRuleLogicControl || "Choice";
      field.appendChild(label);
      let mirror = null;
      if (sourceControl.tagName === "SELECT") {
        mirror = targetObject.document.createElement("select");
        Array.from(sourceControl.options || []).forEach(option => {
          const mirrorOption = targetObject.document.createElement("option");
          mirrorOption.value = option.value;
          mirrorOption.textContent = option.textContent;
          mirrorOption.selected = option.selected;
          mirrorOption.disabled = option.disabled === true;
          mirrorOption.dataset.classicalCanvasOptionAvailability = option.dataset.classicalCanvasOptionAvailability || "";
          mirrorOption.dataset.classicalAuthorityOptionTag = option.dataset.classicalAuthorityOptionTag || "";
          mirror.appendChild(mirrorOption);
        });
        mirror.value = sourceControl.value;
      } else if (sourceControl.type === "checkbox") {
        mirror = targetObject.document.createElement("input");
        mirror.type = "checkbox";
        mirror.checked = sourceControl.checked === true;
      }
      if (!mirror) {
        return null;
      }
      mirror.className = "classical-whole-canvas-choice__control";
      mirror.disabled = sourceControl.disabled === true;
